# database.pyimport osfrom sqlalchemy import create_enginefrom sqlalchemy.orm import sessionmaker, declarative_basefrom config import settings# Resolve Postgres URL (prefer settings.POSTGRES, then generic, then env pieces)PG_URL = (    getattr(settings, "SQLALCHEMY_DATABASE_URL_POSTGRES", None)    or getattr(settings, "SQLALCHEMY_DATABASE_URL", None)    or os.getenv("SQLALCHEMY_DATABASE_URL_POSTGRES")    or "postgresql+psycopg2://{user}:{pw}@{host}:{port}/{db}".format(        user=os.getenv("PG_USER", "postgres"),        pw=os.getenv("PG_PASS", ""),        host=os.getenv("PG_HOST", "localhost"),        port=os.getenv("PG_PORT", "5432"),        db=os.getenv("PG_NAME", "postgres"),    ))# Single Postgres engineengine = create_engine(    PG_URL,    future=True,          # SQLAlchemy 1.4/2.0 style    pool_pre_ping=True,   # validate connections    pool_recycle=3600,    # recycle stale conns    echo=os.getenv("SQL_ECHO", "0") == "1",)# Session factorySessionLocal = sessionmaker(bind=engine, autocommit=False, autoflush=False)# Declarative baseBase = declarative_base()# FastAPI dependencydef get_db():    db = SessionLocal()    try:        yield db    finally:        db.close()